// Index to make the query a single-partition lookup, not a scan
db.orders.createIndex({ "customer.id": 1, createdAt: -1 });

// Equivalent of the SQL 'top customers by spend' via aggregation pipeline
db.orders.aggregate([
  { $match: { status: "paid",
              createdAt: { $gte: ISODate("2026-05-01") } } },
  { $group: { _id: "$customer.id",
              name: { $first: "$customer.name" },
              spendCents: { $sum: "$totalCents" } } },
  { $sort: { spendCents: -1 } },
  { $limit: 5 }
]);

// DynamoDB single-table item: PK groups an aggregate, SK orders/typed within it
// One table holds customers, orders, and order items distinguished by key prefixes.
{
  "PK": "CUST#cust_88",         // partition: everything about this customer
  "SK": "ORDER#2026-06-01#ord_10472",  // sort: orders newest-last within partition
  "Type": "Order",
  "Status": "paid",
  "TotalCents": 8400,
  "GSI1PK": "STATUS#paid",      // secondary index to query orders by status
  "GSI1SK": "2026-06-01T10:22:00Z"
}
// Query: all orders for a customer, newest first, in ONE request:
//   PK = "CUST#cust_88" AND begins_with(SK, "ORDER#")  (ScanIndexForward=false)

// Schema-on-read reality: three documents in one collection, all 'valid'
// to the database, all a landmine for the reader.
{ "_id": 1, "price": 1999 }                 // cents, integer
{ "_id": 2, "price": "19.99" }              // string, dollars
{ "_id": 3, "price": { "amount": 1999, "ccy": "USD" } }  // object

// The reader must defensively handle every historical shape. The schema
// still exists -- it is just enforced by hope and code review, not the engine.
// Mitigation: app-side schema validation (Mongoose, Zod) or MongoDB's
// JSON Schema validators, which reintroduce schema-on-write selectively.

