-- (a) NORMALIZED RELATIONAL SCHEMA
CREATE TABLE customers (
  id    BIGSERIAL PRIMARY KEY,
  name  TEXT NOT NULL
);
CREATE TABLE orders (
  id          BIGSERIAL PRIMARY KEY,
  customer_id BIGINT NOT NULL REFERENCES customers(id),
  status      TEXT NOT NULL,
  total_cents BIGINT NOT NULL,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX idx_orders_cust ON orders (customer_id, created_at DESC);
CREATE INDEX idx_orders_status ON orders (status, created_at DESC);
CREATE TABLE order_items (
  order_id   BIGINT NOT NULL REFERENCES orders(id),
  product_id BIGINT NOT NULL,
  qty        INT NOT NULL,
  PRIMARY KEY (order_id, product_id)
);

-- Pattern 1: customer + their orders newest first
SELECT o.* FROM orders o
WHERE o.customer_id = $1 ORDER BY o.created_at DESC;
-- Pattern 2: one order + its items
SELECT o.*, i.* FROM orders o
JOIN order_items i ON i.order_id = o.id WHERE o.id = $1;
-- Pattern 3: all paid orders for the dashboard
SELECT * FROM orders WHERE status = 'paid' ORDER BY created_at DESC;

/* (b) DYNAMODB SINGLE-TABLE DESIGN
  Base table: PK (partition), SK (sort). GSI1: GSI1PK, GSI1SK.

  Customer item:  PK="CUST#88"            SK="PROFILE"
  Order item:     PK="CUST#88"            SK="ORDER#2026-06-01#10472"
                  GSI1PK="STATUS#paid"    GSI1SK="2026-06-01T10:22:00Z"
  Order-item:     PK="ORDER#10472"        SK="ITEM#sku_12"

  Pattern 1: Query PK="CUST#88" AND begins_with(SK,"ORDER#")  ScanIndexForward=false
  Pattern 2: Query PK="ORDER#10472"  (returns the order header + all ITEM# rows)
  Pattern 3: Query GSI1 where GSI1PK="STATUS#paid" ordered by GSI1SK desc
*/

// SQL VERSION
// SELECT i.category, SUM(i.line_total_cents) AS revenue
// FROM orders o
// JOIN order_items i ON i.order_id = o.id
// WHERE o.status = 'paid'
//   AND o.created_at >= now() - interval '30 days'
// GROUP BY i.category
// ORDER BY revenue DESC
// LIMIT 3;

// MONGODB AGGREGATION (items embedded in each order document)
db.orders.aggregate([
  { $match: {
      status: "paid",
      createdAt: { $gte: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000) }
  }},
  { $unwind: "$items" },                       // explode embedded array -> one doc per item
  { $group: {
      _id: "$items.category",
      revenueCents: { $sum: "$items.lineTotalCents" }
  }},
  { $sort: { revenueCents: -1 } },
  { $limit: 3 }
]);

// Index that lets $match avoid a collection scan:
db.orders.createIndex({ status: 1, createdAt: -1 });
